functions.example:
requirelib("http");
var resp = http.request({url:"https://example.com/api", method:"POST", headers:{"Authorization":"Bearer x"}, json:{a:1}});
if (resp.ok){ console.log(resp.status, resp.body); }

requirelib("sqlite");
var db = sqlite.open("user:/.appdata/myapp/data.sqlite");
db.exec("CREATE TABLE IF NOT EXISTS t (id INTEGER PRIMARY KEY, name TEXT)");
db.close();

requirelib("llm");
var reply = llm.chat("What is 2 + 2?");
sendResp(reply);

requirelib("llm");
var reply = llm.chatWithFile(
    "Describe this image.",
    "user:/Photos/holiday.jpg"
);
sendResp(reply);

requirelib("llm");
var resp = llm.request([
    { role: "system", content: "You are helpful." },
    { role: "user",   content: "Hi!" }
]);
sendResp(resp.choices[0].message.content);

requirelib("llm");
var parts = llm.fileParts(["user:/report.txt"]);
var resp = llm.request([{ role: "user", content: parts }]);
sendResp(resp.choices[0].message.content);

requirelib("cnn");
var r = cnn.classify("user:/cat.jpg", { top_k: 3 });
sendJSONResp(r.data);

requirelib("cnn");
var r = cnn.detect("user:/street.jpg", { score_threshold: 0.3 });
sendJSONResp(r.data);

requirelib("cnn");
var r = cnn.faceLandmarks("user:/face.jpg", { cropped: true });
sendJSONResp(r.data);

requirelib("cnn");
var r = cnn.faceCompare("user:/a.jpg", "user:/b.jpg", { threshold: 0.5 });
sendResp(r.same ? "same" : "different");

requirelib("cnn");
var r = cnn.analyze("user:/group.jpg", ["detect", "faces"], { render: true });
sendJSONResp(r.results);

requirelib("cnn");
var job = cnn.detect("user:/big.jpg", { async: true });
while (job.status === "queued" || job.status === "running") {
    delay(500);
    job = cnn.job(job.id);
}
sendJSONResp(job.result);

requirelib("office");
var r = office.presentationToPptx(data, "user:/Desktop/out.pptx");
if (r){ sendResp("OK"); }

var msg = websocket.read(5000);
if (msg === false) { /* closed */ }
if (msg === null)  { /* timeout  */ }

var last = "";
websocket.onMessage = function(msg) {
    last = msg.data;
};
while (!websocket.isClosed()) {
    if (last !== "") {
        websocket.send("Echo: " + last);
        last = "";
    }
    delay(100);
}

requirelib("notification");
notification.send("Backup done", "Your nightly backup finished");
notification.send("Disk failing", "SMART error on /dev/sda", notification.PRIORITY_HIGH);
